import React from 'react'
import { AiFillSound } from "react-icons/ai";
import { IoIosVolumeOff } from "react-icons/io";
import ReactCardFlip from 'react-card-flip';

const readingdata = [
    {'key': '500', 'd': 'The structure of an atom'},
    {'key': '501', 'd': 'Electron shell of an atom'},
    {'key': '502', 'd': 'Mass spectrometry'},
    {'key': '503', 'd': 'Periodicity'},
    {'key': '504', 'd': 'Bonding'},
    {'key': '505', 'd': 'The enthalpy changes'},
    {'key': '506', 'd': 'The rate of reaction'},
    {'key': '507', 'd': 'Equilibrium'},
    {'key': '508', 'd': 'Alkanes'},
    {'key': '509', 'd': 'Alkanes and sources of hydrocarbons'},
    {'key': '510', 'd': 'Alkenes'},
    {'key': '511', 'd': 'Alcohols'},
    {'key': '512', 'd': 'Halogenoalkanes'},
    {'key': '513', 'd': 'Analytical technique - chromatography'},
    {'key': '514', 'd': 'Analytical Technique - mass spectrometry'},
    {'key': '515', 'd': 'Analytical Technique - infrared spectroscopy'},
    {'key': '516', 'd': 'Analytical technique - NMR spectroscopy'},
    {'key': '517', 'd': 'The Redox Reaction'},
    {'key': '518', 'd': 'Halogens'},
    {'key': '519', 'd': 'The Alkaline Earth elements'},
    {'key': '520', 'd': 'Thermodynamics'}
];


class ReadingSection extends React.Component {

    constructor (props ) {
        super(props);
        this.state = {
            isPaused: false,
            pause1Id: null,
            isPaused2: false,
            pause2Id: null
        }
    }
    render () {
        return (
            <div>
                {readingdata.map((data, id) => 
                    <div key={id}>
                        <ReactCardFlip 
                            key = {"" + id} 
                            isFlipped = {false} 
                            flipDirection = "horizontal">
                                <div className = "Card" >
                                    <h1>{data['d']}</h1>
                                    <audio
                                        ref={(audio1) => { this[data['key']] = audio1 }}
                                        src={require('./' + data['key'] + '.mp3')}/>
                                        <h3  onClick={() => {
                                            if (this.state.pause1Id != null && this.state.pause1Id != id) {
                                                this[data['key']].load();
                                            }
                                            console.log('./' + data['key'] + '.mp3')
                                            this.setState({pause1Id: this.state.pause1Id != null ? null : id }, () => {
                                                if (this.state.pause1Id == id) {
                                                    this[data['key']].play()
                                                } else {
                                                    this[data['key']].pause()
                                                }
                                            })
                                        }}> 
                                            {this.state.pause1Id == id ? <AiFillSound /> : <IoIosVolumeOff />}
                                        </h3>
                                </div>
                                <div className = "Flip">
                                    <p onClick = {()=>{
                                        this.setState({isFlipped: true, isPaused2: false})
                                        this.music.pause();
                                    }}>{this.props.definition}  </p>
                                    <audio 
                                        ref={(music) => { this.music = music }}
                                        autoPlay={this.state.button2}  src={require('./' + data['key'] + '.mp3')}/>
                                    <h3 
                                        className = "Logo" 
                                        onClick={()=>{
                                            this.setState({isPaused2: !this.state.isPaused2},()=>{
                                            if (this.state.isPaused2) {
                                                this.music.play()
                                            } else {
                                                this.music.pause()
                                            }
                                        })
                                    }}> 
                                        {this.state.isPaused2 ? <AiFillSound /> : <IoIosVolumeOff />}
                                    </h3>   
                            </div>
                        </ReactCardFlip>
                    </div>
                )}
            </div>
        ); 
    }
}

export default ReadingSection;