import React from 'react';
import Elements from './elements';
import './App.css'
import ReactSearchBox from 'react-search-box'
import {Link} from 'react-router-dom';

export default class Eblan extends React.Component {
    
  
    componentWillMount() {
        if (this.props.location.data == undefined) {
            window.location.href = "/"
        }
        console.log(this.state.newEnd);
    }
    state = {
        newEnd: this.props.location.data.theme,
        endEnd: this.props.location.data.theme,
    }
     render () {
         return (
        <div className="Container">
            <Link to="/" className="back_btn1">Home</Link>
            <h1>
                {this.props.location.data.title}
            </h1>
            <ReactSearchBox
          placeholder="Введите слово..."
          data={this.props.location.data.theme}
          onSelect={record => {
              var newObj = [];
              newObj.push(record);
              console.log(record);
              this.setState({
                  newEnd:newObj,
              })
              
          }}
          onFocus={() => {
            console.log('This function is called when is focussed')
          }}
          
          onChange={value => {
              if (value == '' ) {
                  console.log("empty");
                  var mal = this.state.endEnd;
                  this.setState({
                      newEnd: mal,
                  })
              }
          }}
          fuseConfigs={
              {
            threshold: 0.05,
          }
        }
        />
            <Elements className = "Qotaq" contents = {this.state.newEnd} />
        </div>
        )
    }
}