import React from 'react'
import './Tables.css'
import data from './data.json'
import './App.css'
import {Link} from 'react-router-dom';
let host = "./"

class Row extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      music: null
    }
    this.audio = new Audio()
  }
  render () {
    let {key, description, value} = this.props.object
    return (
      <tr className="Row">
          <td>{value}</td>
          <td onClick={()=>{
            if (this.state.music == key) {
              this.audio.pause()
              this.setState({music: null})
            } else {
              this.audio = new Audio(require(host + key + ".mp3"))
              console.log()
              this.audio.play()
              this.setState({music: key})
            }
          }}>
            {description}
          </td>
      </tr>
    )
  }
}


class Table extends React.Component {
  render () {

    let {termName, index} = this.props
    return (
      <div className="Table">
          <h2>{index + 1}. {termName}</h2>
          <table>
              { data[termName].array.map((object, index) =>
                  <Row object={object} key={index}/>
              )}
          </table>
      </div>
    )
  }
}

export default class Tables extends React.Component {
  render () {
    return (
      <div className="Tables">
          <Link to="/" className="back_btn">Home</Link>
          <h1>16. Chemical Calculations</h1>
          {Object.keys(data).map((termName, i)=>
              <Table key={i} index={i} termName={termName}/>
          )}
      </div>
    )
  }
}
