import React from 'react';
import ReactAudioPlayer from 'react-audio-player';
import './Person.css';
import ReactCardFlip from 'react-card-flip';
import { AiFillSound } from "react-icons/ai";
import { IoIosVolumeOff } from "react-icons/io";

class Element extends React.Component {
    constructor(props) {
        super(props);
        this.state = {
            button: false,
            button2: false,
            isFlipped: false,
            flipped: false,
        };
        this.handleClick = this.handleClick.bind(this);
        this.audio = {}
        this.music = {}
    }
    handleClick(e) {
        
        e.preventDefault();
        this.setState(prevState => ({ isFlipped: !prevState.isFlipped }));
        // var flip = this.state.flipped;
        // this.setState({flipped:!flip})
        // console.log(this.state.flipped);
      }
    
    render() {
       
        return (
           <ReactCardFlip key = {this.props.word} isFlipped = {this.state.isFlipped} flipDirection = "horizontal">
             <div className = "Card" >
             <p onClick = {()=>{
                 var flip = this.state.isFlipped;
                 this.setState({isFlipped: !flip, button: false})
                 this.audio.pause();
             }} > {this.props.word} </p>
             
                    <audio
                    ref={(audio) => { this.audio = audio }}
                     autoPlay={this.state.button}  src={require('./' + this.props.huli + '.mp3')}/>
                <h3  onClick={()=>{
                    // console.log(this.state.isFlipped);
                        this.setState({button: !this.state.button},()=>{
                        if (this.state.button) {
                        // console.log('i play');
                        this.audio.play()
                    }else {
                        // console.log('flipped');
                        this.audio.pause()
                      }
                     })
    }}> {this.state.button ? <AiFillSound /> : <IoIosVolumeOff />}</h3>   
                   
             </div>
             
             <div className = "Flip">
             <p onClick = {()=>{
                 var flip = this.state.isFlipped;
                 this.setState({isFlipped: !flip, button2: false})
                 this.music.pause();
             }}>{this.props.definition}  </p>
                    <audio 
                    ref={(music) => { this.music = music }}
                     autoPlay={this.state.button2}  src={require('./' + this.props.huli + 'd.mp3')}/>
                <h3 className = "Logo" onClick={()=>{
                        this.setState({button2: !this.state.button2},()=>{
                        if (this.state.button2) {
                        this.music.play()
                    } else {
                        this.music.pause()
                    }
                     })
    }}> {this.state.button2 ? <AiFillSound /> : <IoIosVolumeOff />}</h3>   
                   
             </div>
           </ReactCardFlip>
        )
    }
}
export default Element;
