import React from 'react';
import './Person.css';
import {Link} from 'react-router-dom';
const Person = (sts) => {

    return (
        <Link style={{textDecoration: "none"}} to={{
            pathname: sts.index === 15 ? "/audio" : "/settings",
            data: {
             theme: sts.data,
             title: sts.name
            }
         }}>
            <div className = 'Person' onClick = {sts.clicked}>
                <h1 className="backgroundNumber">Unit: {sts.index + 1}</h1>
                <p>{sts.name}</p>
            </div>
        </Link>
    )
    
}
export default Person;